String favor="";
if("non_favor".equals(is_favor)){
	favor="<img src=\"images/star_off.gif\" style='padding-left:1px;padding-right:5px;float:left;width:15px;height:15px;cursor: pointer;' title=\"点击收藏\" onclick=\"invokeServerAction('com.customer.personalize.FavorPage',{pageid:'"+page_id+"'},InvokeCallbackMethod_refreshTitle,null);\">";
}else{
	favor="<img src=\"images/star_on.gif\" style='padding-left:1px;padding-right:5px;float:left;width:15px;height:15px;cursor: pointer;' title=\"取消收藏\" onclick=\"invokeServerAction('com.customer.personalize.FavorPage',{pageid:'"+page_id+"'},InvokeCallbackMethod_refreshTitle,null);\">";
}
title=favor+"<font style='color:#154BA0'>"+menu_name+"</font>>><font style='font-weight:bold;color:#154BA0'>"+page_name+"</font>";
